        <div id="submit-ticket" class="subsection"><h3 class="subsection__title">Submit a Support Ticket</h3><div class="ticket-form"><label>Category</label><select><option>Select a category…</option><option>Access &amp; Permissions</option><option>Data Quality Issue</option><option>Query / API Problem</option><option>Pipeline / Ingestion</option><option>Feature Request</option><option>General Question</option></select><label>Subject</label><input type="text" placeholder="Brief description of your issue"><label>Description</label><textarea placeholder="Provide as much detail as possible…"></textarea><label>Priority</label><select><option>Normal</option><option>High — blocking my work</option><option>Low — nice to fix</option></select><button class="btn btn--accent" onclick="alert('Ticket submitted! Our team will respond within 1 business day.')">Submit Ticket</button></div></div>
      </section>

